import { Flex, useBreakpointValue } from '@chakra-ui/react';
import { SourceFrequency } from '@domain/entry';
import { PublicActionPage } from '@domain/publicActionPage';
import { PaymentMethodForm } from '@ui/components/formControls/compositions/PaymentMethodForm';
import { FormDateTimeControl } from '@ui/components/formControls/DateTimeControl';
import { FormInputControl } from '@ui/components/formControls/InputControl';
import { OrderOfSourceFrequencies } from '@ui/components/organisms/Funds/DonationSelector';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { FrequencySelector } from '../FrequencySelector/FrequencySelector';

type Props = {
  actionPage: PublicActionPage;
  isCvvRequired?: boolean;
  showFutureProcessDate?: boolean;
  showSourceCode?: boolean;
};

export const PaymentFields = ({
  actionPage,
  isCvvRequired,
  showFutureProcessDate = true,
  showSourceCode = true,
}: Props) => {
  const { t } = useTranslation(['common', 'customFields', 'finance']);
  const showSwitchTitles = useBreakpointValue({ base: false, md: true });
  const isCvvRequiredInternal =
    isCvvRequired !== undefined
      ? isCvvRequired
      : !actionPage.account.accountConfiguration.disableCvv;

  const frequencies = useMemo(
    () => actionPage.amountConfiguration?.recurringOptions?.map((option) => option) || [],
    [actionPage.amountConfiguration?.recurringOptions]
  );

  const options = useMemo(
    () =>
      frequencies
        .sort((a, b) => OrderOfSourceFrequencies.indexOf(a) - OrderOfSourceFrequencies.indexOf(b))
        .map((frequency) => ({
          label:
            frequency === SourceFrequency.Once
              ? t(`common:frequency.onetime`)
              : t(`common:frequency.${frequency}`),
          value: frequency,
        })),
    [frequencies, t]
  );

  const showFrequencySwitch =
    options.length > 0 && !(options.length === 1 && options[0].value === SourceFrequency.Once);

  return (
    <Flex flexDirection="column">
      <Flex flexDirection="column">
        <PaymentMethodForm
          allowedPaymentMethods={{
            bankAccount: true,
            creditCard: true,
          }}
          cardZipRequired
          cvvRequired={isCvvRequiredInternal}
          showBillingAddress={false}
          showCardholderName={false}
          showCardZip
          showCreditCardInformationTitle={false}
          showSwitchTitles={showSwitchTitles}
          useLongCaptions
        />
      </Flex>
      {showFrequencySwitch ? <FrequencySelector options={options} /> : null}
      {showFutureProcessDate || showSourceCode ? (
        <Flex gap={3} marginTop={showFrequencySwitch ? 8 : 0}>
          {showFutureProcessDate ? (
            <FormDateTimeControl
              label={t('finance:virtualTerminal.futureProcessDate')}
              name="captureAt"
              type="fullDate"
              variant="floating"
            />
          ) : null}
          {showSourceCode && (
            <FormInputControl
              label={t('finance:virtualTerminal.sourceCode.label')}
              name="sourceCode"
              placeholder={t('finance:virtualTerminal.sourceCode.placeholder')}
              variant="permafloating"
            />
          )}
        </Flex>
      ) : null}
    </Flex>
  );
};

