export const MultiSwitch = ({
  buttonClassName,
  buttonInnerClassName,
  buttonProps,
  className,
  options,
  selectedOption,
  setSelectedOption,
  variant = 'default',
}: MultiSwitchProps) => {
  const buttonClasses = clsx(
    'whitespace-nowrap p-[8px] pe-3 ps-3',
    buttonClassName && buttonClassName
  );

  const switchInnerClasses = clsx(
    'overflow-hidden text-ellipsis',
    buttonInnerClassName && buttonInnerClassName
  );

  return (
    <div className={wrapperClasses({ className, variant })}>
      {options.length === 1 ? (
        <MultiSwitchButton
          id={options[0]?.value}
          onClick={() => setSelectedOption(0)}
          selected
          switchButtonClassName={buttonClasses}
          switchButtonInnerClassName={switchInnerClasses}
          title={options[0]?.title}
          variant={variant}
        >
          {options[0].label}
        </MultiSwitchButton>
      ) : (
        options.map((option, idx) => (
          <MultiSwitchButton
            id={option.value}
            key={option.value}
            onClick={() => setSelectedOption(idx)}
            selected={idx === selectedOption}
            switchButtonClassName={buttonClasses}
            switchButtonInnerClassName={switchInnerClasses}
            title={option.title}
            variant={variant}
            {...buttonProps}
          >
            {option.label}
